 56	/* LMP90xxx upper (URA) and lower (LRA) register addresses */
 57	#define LMP90XXX_URA(addr) ((addr >> 4U) & GENMASK(2, 0))
 58	#define LMP90XXX_LRA(addr) (addr & GENMASK(3, 0))
